from dataclasses import dataclass, field
from typing import Literal

StepType = Literal["reasoning", "tool_use", "tool_result", "final_reply"]

@dataclass
class TrajectoryStep:
    type: StepType
    content: str
    tool_name: str | None = None
    tool_input: dict | None = None
    tool_result: str | None = None
    error: str | None = None

@dataclass
class AgentTrajectory:
    request_id: str
    user_input: str
    steps: list[TrajectoryStep] = field(default_factory=list)
    final_output: str = ""

def extract_trajectory(messages: list[dict]) -> AgentTrajectory:
    """Parse Anthropic API message history into a structured trajectory."""
    trajectory = AgentTrajectory(
        request_id=__import__("uuid").uuid4().hex,
        user_input="",
    )
    for msg in messages:
        role = msg.get("role")
        content = msg.get("content", [])
        if isinstance(content, str):
            content = [{"type": "text", "text": content}]
        for block in content:
            btype = block.get("type")
            if role == "user" and btype == "text" and not trajectory.user_input:
                trajectory.user_input = block["text"]
            elif role == "user" and btype == "tool_result":
                trajectory.steps.append(TrajectoryStep(
                    type="tool_result",
                    content=str(block.get("content", "")),
                    tool_result=str(block.get("content", "")),
                    error=block.get("content") if block.get("is_error") else None,
                ))
            elif role == "assistant" and btype == "text":
                trajectory.steps.append(TrajectoryStep(
                    type="reasoning",
                    content=block["text"],
                ))
            elif role == "assistant" and btype == "tool_use":
                trajectory.steps.append(TrajectoryStep(
                    type="tool_use",
                    content=str(block.get("input", {})),
                    tool_name=block.get("name"),
                    tool_input=block.get("input", {}),
                ))
    if trajectory.steps and trajectory.steps[-1].type == "reasoning":
        last = trajectory.steps.pop()
        trajectory.final_output = last.content
        trajectory.steps.append(TrajectoryStep(type="final_reply", content=last.content))
    return trajectory

def eval_tool_call(
    user_input: str,
    step: TrajectoryStep,
    available_tools: list[str],
) -> dict:
    """
    Score a tool call on three dimensions:
    - tool_choice: did the agent pick the right tool?
    - arg_quality: are the arguments correct and complete?
    - necessity: was the tool call necessary at this point?
    """
    if step.tool_name not in available_tools:
        return {"tool_choice": 0.0, "arg_quality": 0.0, "necessity": 0.0}

    prompt = (
        f"User request: {user_input}\n"
        f"Tool called: {step.tool_name}\n"
        f"Arguments: {step.tool_input}\n"
        f"Available tools: {available_tools}\n\n"
        "Rate each dimension 0.0-1.0:\n"
        "- tool_choice: was this the right tool for the situation?\n"
        "- arg_quality: are the arguments correct, complete, and precise?\n"
        "- necessity: was this call necessary (not redundant with prior steps)?\n"
        'Return JSON: {"tool_choice": 0.0, "arg_quality": 0.0, "necessity": 0.0}'
    )
    import json, re
    msg = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=64,
        messages=[{"role": "user", "content": prompt}],
    )
    m = re.search(r'\{[^}]+\}', msg.content[0].text)
    if not m:
        return {"tool_choice": 0.0, "arg_quality": 0.0, "necessity": 0.0}
    try:
        return json.loads(m.group())
    except json.JSONDecodeError:
        return {"tool_choice": 0.0, "arg_quality": 0.0, "necessity": 0.0}

import math
from statistics import mean

def aggregate_trajectory(
    step_scores: list[float],
    use_compound: bool = False,
) -> float:
    """
    Aggregate step scores into a single trajectory score.
    use_compound=True: product of scores — a single 0.0 zeroes the whole trajectory.
    use_compound=False: mean — averages out isolated mistakes.
    """
    if not step_scores:
        return 0.0
    if use_compound:
        product = 1.0
        for s in step_scores:
            product *= s
        return product
    return mean(step_scores)

def eval_full_trajectory(
    trajectory: AgentTrajectory,
    available_tools: list[str],
) -> dict:
    """Run step-level evals and return a trajectory scorecard."""
    reasoning_scores, tool_scores = [], []
    error_steps = 0

    for i, step in enumerate(trajectory.steps):
        prior = trajectory.steps[:i]
        if step.type == "reasoning":
            s = eval_reasoning_step(trajectory.user_input, prior, step)
            reasoning_scores.append(s)
        elif step.type == "tool_use":
            scores = eval_tool_call(trajectory.user_input, step, available_tools)
            tool_scores.append(mean(scores.values()))
        elif step.type == "tool_result" and step.error:
            error_steps += 1

    all_scores = reasoning_scores + tool_scores
    return {
        "mean_step_score": mean(all_scores) if all_scores else 0.0,
        "compound_score": aggregate_trajectory(all_scores, use_compound=True),
        "reasoning_score": mean(reasoning_scores) if reasoning_scores else 1.0,
        "tool_score": mean(tool_scores) if tool_scores else 1.0,
        "total_steps": len(trajectory.steps),
        "error_steps": error_steps,
        "error_rate": error_steps / len(trajectory.steps) if trajectory.steps else 0.0,
    }

import json
from pathlib import Path
from datetime import datetime

TRAJECTORY_LOG = Path("logs/trajectories.jsonl")

class TrajectoryRecorder:
    def __init__(self, request_id: str, user_input: str) -> None:
        self.request_id = request_id
        self.user_input = user_input
        self.steps: list[dict] = []
        self.started_at = datetime.utcnow().isoformat()

    def record_reasoning(self, text: str) -> None:
        self.steps.append({"type": "reasoning", "content": text})

    def record_tool_call(self, name: str, args: dict) -> None:
        self.steps.append({"type": "tool_use", "tool_name": name, "args": args})

    def record_tool_result(self, result: str, error: bool = False) -> None:
        self.steps.append({"type": "tool_result", "content": result, "error": error})

    def record_final_reply(self, text: str) -> None:
        self.steps.append({"type": "final_reply", "content": text})

    def flush(self) -> None:
        record = {
            "request_id": self.request_id,
            "user_input": self.user_input,
            "started_at": self.started_at,
            "steps": self.steps,
        }
        TRAJECTORY_LOG.parent.mkdir(exist_ok=True)
        with open(TRAJECTORY_LOG, "a") as f:
            f.write(json.dumps(record) + "\n")
